```hcl
# Minimal IAM role plus attachment of the AWS managed SecurityAudit policy
resource "aws_iam_role" "example" {
  name               = "<example_resource_name>"
  assume_role_policy = <<POLICY
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": { "AWS": "arn:aws:iam::<example_account_id>:root" },
      "Action": "sts:AssumeRole"
    }
  ]
}
POLICY
}

resource "aws_iam_role_policy_attachment" "security_audit" {
  role       = aws_iam_role.example.name
  policy_arn = "arn:aws:iam::aws:policy/SecurityAudit" # CRITICAL: attaches SecurityAudit to the role to pass the check
}
```

```hcl
# IAM role with AWS Support access
resource "aws_iam_role" "example_resource_name" {
  name               = "example_resource_name"
  assume_role_policy = jsonencode({
    Version   = "2012-10-17",
    Statement = [{
      Effect    = "Allow",
      Principal = { AWS = "arn:aws:iam::<example_account_id>:user/<example_resource_name>" },
      Action    = "sts:AssumeRole"
    }]
  })

  managed_policy_arns = [
    "arn:aws:iam::aws:policy/AWSSupportAccess"  # Critical: ensures this role has AWSSupportAccess (PASS)
  ]
}
```

```hcl
# Attach an inline policy to block long-term creds from non-IAM/STS services
resource "aws_iam_user_policy" "deny_non_iam_sts_longterm" {
  name = "DenyNonIamStsWithLongTermCreds"
  user = "<example_resource_name>"  # Critical: target the affected IAM user

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Effect    = "Deny"
      NotAction = ["iam:*", "sts:*"]
      Resource  = "*"
      Condition = {
        Null = { "aws:TokenIssueTime" = "true" } # Critical: denies when no session token (long-lived creds)
      }
    }]
  })
}
```

```hcl
# Disable ACLs by enforcing bucket owner for all objects
resource "aws_s3_bucket_ownership_controls" "<example_resource_name>" {
  bucket = "<example_resource_id>"
  rule {
    object_ownership = "BucketOwnerEnforced" # Critical: Disables ACLs and enforces bucket owner
  }
}
```

```hcl
# Terraform: restrict bucket policy to this AWS account only
resource "aws_s3_bucket_policy" "<example_resource_name>" {
  bucket = "<example_resource_name>"
  policy = jsonencode({
    Version   = "2012-10-17"
    Statement = [{
      Effect    = "Allow"
      Principal = { AWS = "arn:aws:iam::<example_resource_id>:root" } # Critical: limits access to the bucket owner's account, preventing cross-account access
      Action    = "s3:*"
      Resource  = [
        "arn:aws:s3:::<example_resource_name>",
        "arn:aws:s3:::<example_resource_name>/*"
      ]
    }]
  })
}
```

```hcl
# Enable versioning and minimal CRR to a bucket in another region
resource "aws_s3_bucket" "source" {
  bucket = "<example_resource_name>"

  versioning {                      
    enabled = true  # critical: required for replication
  }

  replication_configuration {        
    role = aws_iam_role.replication.arn  # critical: role used by S3 to replicate

    rules {
      status = "Enabled"  # critical: replication rule must be enabled
      destination {
        bucket = "arn:aws:s3:::<example_destination_bucket_name>"  # critical: destination bucket ARN in a different region
      }
    }
  }
}

resource "aws_iam_role" "replication" {
  name = "<example_resource_name>-s3-replication-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Effect    = "Allow"
      Principal = { Service = "s3.amazonaws.com" }
      Action    = "sts:AssumeRole"
    }]
  })
}

resource "aws_iam_role_policy" "replication" {
  name = "<example_resource_name>-s3-replication-policy"
  role = aws_iam_role.replication.id
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect = "Allow",
        Action = ["s3:ListBucket", "s3:GetReplicationConfiguration"],
        Resource = "arn:aws:s3:::${aws_s3_bucket.source.bucket}"
      },
      {
        Effect = "Allow",
        Action = [
          "s3:GetObjectVersionForReplication",
          "s3:GetObjectVersionAcl",
          "s3:GetObjectVersionTagging"
        ],
        Resource = "arn:aws:s3:::${aws_s3_bucket.source.bucket}/*"
      },
      {
        Effect = "Allow",
        Action = ["s3:ReplicateObject", "s3:ReplicateDelete", "s3:ReplicateTags"],
        Resource = "arn:aws:s3:::<example_destination_bucket_name>/*"
      }
    ]
  })
}
```

```hcl
resource "aws_s3_bucket" "<example_resource_name>" {
  bucket = "<example_resource_name>"
}

resource "aws_s3_bucket_server_side_encryption_configuration" "<example_resource_name>" {
  bucket = aws_s3_bucket.<example_resource_name>.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"  # Critical: enables default SSE-S3 for the bucket
    }
  }
}
```

```hcl
# Enable default SSE-KMS on an existing S3 bucket
resource "aws_s3_bucket_server_side_encryption_configuration" "<example_resource_name>" {
  bucket = "<example_bucket_name>"

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "aws:kms" # Critical: enforces SSE-KMS by default
    }
  }
}
```

```hcl
# Minimal lifecycle configuration to mark the bucket as having an enabled rule
resource "aws_s3_bucket_lifecycle_configuration" "<example_resource_name>" {
  bucket = "<example_resource_name>"

  rule {
    status = "Enabled"  # CRITICAL: Enables lifecycle rule to pass the check
    filter {}            # Applies to all objects

    abort_incomplete_multipart_upload {
      days_after_initiation = 7  # Minimal action to satisfy schema
    }
  }
}
```

```hcl
resource "aws_s3_bucket_object_lock_configuration" "<example_resource_name>" {
  bucket               = "<example_resource_name>"
  object_lock_enabled  = "Enabled"  # CRITICAL: Enables Object Lock configuration on the bucket
  rule {
    default_retention {
      mode = "GOVERNANCE"  # CRITICAL: Default retention mode
      days = 1              # CRITICAL: Minimal retention period
    }
  }
}
```

```hcl
# Enable versioning on an existing S3 bucket
resource "aws_s3_bucket_versioning" "<example_resource_name>" {
  bucket = "<example_resource_name>"
  versioning_configuration {
    status = "Enabled"  # Critical: enables bucket versioning to remediate the finding
  }
}
```

```hcl
# Deny non-SSL (HTTP) requests to the S3 bucket
resource "aws_s3_bucket_policy" "policy" {
  bucket = "<example_resource_name>"
  policy = jsonencode({
    Version   = "2012-10-17"
    Statement = [{
      Effect    = "Deny"
      Principal = "*"
      Action    = "s3:*"
      Resource  = "arn:aws:s3:::<example_resource_name>/*"
      Condition = {
        Bool = {
          "aws:SecureTransport" = "false" # Critical: deny requests not using SSL/TLS
        }
      }
    }]
  })
}
```

REMEDIATION_CODE_OTHER:
1. In the AWS Console, go to S3 and open the bucket <example_resource_name>
2. Select the Permissions tab and click Edit in Bucket policy
3. Paste this policy, replacing the bucket name:
   ```
   {
     "Version": "2012-10-17",
     "Statement": [
       {
         "Effect": "Deny",
         "Principal": "*",
         "Action": "s3:*",
         "Resource": "arn:aws:s3:::<example_resource_name>/*",
         "Condition": { "Bool": { "aws:SecureTransport": "false" } }
       }
     ]
   }
   ```
4. Click Save changes

